// import { Link, useHistory } from "react-router-dom";
import React, { useState, useCallback, useEffect } from "react";
import { useTransition, animated } from "react-spring";
import "./styles.css";
import slider1 from "./fido_finder.png";
import slider2 from "./GG_meta_img.png";
import slider3 from "./airbnb_og_meta.png";
import { TiArrowLeftOutline, TiArrowRightOutline } from "react-icons/ti";

const pages = [
  ({ style }) => {
    return (
      <animated.div
        style={{
          ...style,
          backgroundImage: `url(${slider1})`,
        }}
        className="div__feature_bg"
      ></animated.div>
    );
  },
  ({ style }) => (
    <animated.div
      style={{
        ...style,
        backgroundImage: `url(${slider2})`,
      }}
      className="div__feature_bg"
    ></animated.div>
  ),
  ({ style }) => (
    <animated.div
      style={{
        ...style,
        backgroundImage: `url(${slider3})`,
      }}
      className="div__feature_bg"
    ></animated.div>
  ),
];

const pageLinks = [
  "https://fidofinderapp.herokuapp.com/",
  "https://greengrab.herokuapp.com/",
  "https://collegebnb1.herokuapp.com/",
];

export default function Slider() {
  const [index, set] = useState(0);

  const onClick = useCallback(
    () => set((state) => (state + 1) % pages.length),
    []
  );
  const [paused, setPaused] = useState(false);
  const [reelIntervalId, setIntervalId] = useState();

  const onClickNeg = useCallback(
    () =>
      set((state) => {
        if (state === 0) return pages.length - 1;
        else return state - 1;
      }),
    []
  );
  const transitions = useTransition(index, (p) => p, {
    from: {
      opacity: 0.2,
      // width: "1%",
      // height: "25%",
      transition: "all 0.52s linear",
      transform: "translate3d(50%,0,0)",
    },
    enter: {
      opacity: 1,

      transform: "translate3d(0%,0,0)",
      // transition: "all 0.72s linear",
    },
    leave: {
      opacity: 0,
      transform: "translate3d(-50%,0,0)",
      // transition: "all 0.54s linear",
    },
  });

  useEffect(() => {
    if (paused) {
      clearInterval(reelIntervalId);
      return setIntervalId(null);
    } else {
      return setIntervalId(setInterval(onClick, 3900));
    }
  }, [paused]);

  return (
    <div
      className="slider_container"
      onMouseEnter={() => {
        return setPaused(true);
      }}
      onMouseLeave={() => {
        return setPaused(false);
      }}
    >
      <div className="simple-trans-main">
        <a href={pageLinks[index]}>
          {transitions.map(({ item, props, key }) => {
            const Page = pages[item];
            return <Page key={key} style={props} />;
          })}
        </a>
      </div>
      <div className="div__arrows">
        <TiArrowLeftOutline onClick={onClickNeg} />
        <TiArrowRightOutline onClick={onClick} />
      </div>
    </div>
  );
}
