import { useState, useRef, useEffect } from "react";
import "./App.css";
import "./css/main.css";
import FeaturedProjects from "./components/FeaturedProjects";
import AboutMe from "./components/AboutMe";

function App() {
  const [navBarStyle, setNavBarStyle] = useState({});
  const [collapse, setCollapse] = useState(false);
  const [fadeIn, setFadeIn] = useState({
    opacity: 0,
  });
  const div__aboutMe_Ref = useRef(null);

  function changeCss() {
    const calculatedOpacity = Number(
      1 - this.scrollY / this.innerHeight
    ).toFixed(1);
    const newOpacity = calculatedOpacity > 0 ? calculatedOpacity : 0;

    // setStyle({
    //   opacity: newOpacity,
    // });
    // setFadeIn({
    //   opacity: 1 - newOpacity,
    // });
    if (this.scrollY > this.innerHeight / 5) {
      setNavBarStyle({
        height: "25vh",
        overflow: "none",
      });
      setCollapse(true);
    }
    if (this.scrollY > this.innerHeight) {
      // setStyle({
      //   opacity: 0,
      // });
      // setFadeIn({
      //   opacity: 1,
      //   display: "flex",
      // });
    }
  }
  useEffect(() => {
    if (div__aboutMe_Ref && div__aboutMe_Ref.current) {
      window.addEventListener("scroll", changeCss, false);
    }
  }, [div__aboutMe_Ref]);

  return (
    <div ref={div__aboutMe_Ref} className="App">
      <div style={navBarStyle} className="div__aboutMe">
        <AboutMe collapse={collapse} />
      </div>

      {/* <div style={fadeIn} className="div__content-fade-in"> */}
      <FeaturedProjects />
    </div>
    // </div>
  );
}

export default App;
